const Q_PHYSICS_2019_MODEL_I=[{"id": "objective>Physics>2019 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Electrons were discovered by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dalton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">James Charwick</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J.J. Thompson</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Niels Bohr</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electrons were discovered by J.J. Thomson in 1897. He conducted experiments with cathode ray tubes and measured the mass-to-charge ratio of the particles in the cathode rays. Based on his findings, he concluded that these particles were negatively charged and much smaller than atoms. Thomson named them electrons.</div>", "topic": "ELEMENTARY MODERN PHYSICS : ELEMENTARY STRUCTURE OF THE ATOM"}, {"id": "objective>Physics>2019 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is/are the limitations to the Rutherford's atomic models? <br/> I. It is applicable when energy is radiated as electrons are revolving <br/> II. It is applicable when energy is radiated in a continuous made <br/> III. It is applicable to an atom with only one electron in the other shell.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I & II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II & III only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rutherford assumed that (I) energy is radiated when electrons are revolving (II) energy us radiated in a continuous mode. <br/> These are limitation of Rutherford's model.</div>", "topic": "ELEMENTARY MODERN PHYSICS : MODELS OF THE ATOM AND THEIR LIMITATIONS"}, {"id": "objective>Physics>2019 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a slide wire bridge, the balance is obtained at a point 25cm from one end of a wire 1m long. The resistance to be tested is connected to that end and a standard resistance of 3.6Ω is connected to the other end of the wire. Determine the value of the unknown resistance </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.2Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.2Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.4Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.21Ω</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2019 Model I/img1.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<hr size=\"1\" />3.6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">25<hr size=\"1\" />75</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td></tr></table></div> <br/> 3R = 3.6 <br/> ∴ R = 1.2Ω <br/> </div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>2019 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following equation is the correct definition of the reactance of an inductor L?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Reactance = (Amplitude of voltage) ÷ (Amplitude of Current)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reactance = (Amplitude of voltage) × (Amplitude of current)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reactance = (Amplitude of current)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> ÷ (Amplitude of voltage)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reactance = (Amplitude of current)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> ÷ (Amplitude of voltage)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1/2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Reactance is the value of an inductor or a capacitor in ohms.</div>", "topic": "SIMPLE A. C. CIRCUITS : INDUCTOR - INDUCTIVE REACTANCE"}, {"id": "objective>Physics>2019 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ripple in a power supply unit is caused by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">using an alternating current source </div>", "<div style=\"font-family:Cambria;font-size:17px;\">forward voltage drop </div>", "<div style=\"font-family:Cambria;font-size:17px;\">heavy load </div>", "<div style=\"font-family:Cambria;font-size:17px;\">using a zener diode</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ripple in a power supply unit is caused by using an alternating current source. Ripple refers to the small fluctuations in output voltage in a power supply unit that occur when a direct current (DC) signal is derived from an alternating current (AC) source. This is because AC voltage alternates between positive and negative values, while DC voltage is constant.</div>", "topic": "INTRODUCTORY ELECTRONICS : DIODES"}, {"id": "objective>Physics>2019 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the temperature of a liquid is increased, its surface tension </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain constant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases then decreases </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the temperature of a liquid is increased, its surface tension decreases. Surface tension is the property of a liquid that allows it to resist an external force. It is caused by the cohesive forces between liquid molecules. As the temperature increases, the kinetic energy of the molecules increases, causing them to move more rapidly and thus reducing the cohesive forces between them, which in turn reduces the surface tension.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2019 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The distance between an object and its real image in a convex lens is 40cm. If the magnification of the image is 3, calculate the focal length of the lens</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6,5cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.5cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.5cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">u + v = 40, <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v<hr size=\"1\" />u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3</td></tr></table></div> <br/> v = 3u <br/> u + 3u = 40, 4u = 40, u = 10cm <br/> v = 3u = 30cm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">uv<hr size=\"1\" />u+v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10(30)<hr size=\"1\" />10+30</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">300<hr size=\"1\" />40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">7.5cm</td></tr></table></div></div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2019 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Lamps in domestic lightings are usually in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Series </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Divergent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Parallel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Convergent</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lamps in lightings are arranged in parallel to reduce the heat losses <br/> - resultant resistance is small for parallel arrangement which indicate low heat losses (Heat αR)</div>", "topic": "CURRENT ELECTRICITY : RESISTANCE IN SERIES AND IN PARALLEL"}, {"id": "objective>Physics>2019 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ray of light passes through the centre of curvature of a concave mirror and strikes the mirror. At what angle is the ray reflected?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">180°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60°</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- a ray of light passing through the centre of curvature is returned along the same path <br/> - angle difference along the same path is zero.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2019 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pin-hole camera produces a less sharply defined image when the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pin-hole is larger </div>", "<div style=\"font-family:Cambria;font-size:17px;\">illumination is less </div>", "<div style=\"font-family:Cambria;font-size:17px;\">screen is further from the pin-hole </div>", "<div style=\"font-family:Cambria;font-size:17px;\">object is further from the pin-hole </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- a less sharp or blurred image is due to increased brightness <br/> - increase brightness is also due to large hole or many pin holes.</div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2019 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The value of T in the figure above is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10.0N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Tsin30 + Tsin30 = 40 <br/> 2Tsin30 = 40 <br/> Tsin30 = 40/2 = 20 <br/> T(1/2) = 20 <br/> T = 20 × 2 = 40N</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2019 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A straight wire 15cm long, carrying a current of 6.0A is in a uniform field of 0.40T. What is the force on the wire when it is at right angle to the field.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.46N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.35N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.36N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.24N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The force on a current-carrying wire in a magnetic field is given by the formula F = BILsinθ, where B is the magnetic field strength, I is the current, L is the length of the wire, and θ is the angle between the current and the magnetic field. In this case, the wire is at right angles to the field, so sinθ = 1. Substituting the given values into the formula gives F = 0.40T * 6.0A * 0.15m = 0.36N.</div>", "topic": "MAGNETIC FIELD : FORCE ON A CURRENT-CARRYING CONDUCTOR"}, {"id": "objective>Physics>2019 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pitch of a screw jack is 0.45cm and the arm is 60cm long. If the efficiency of the Jack is 75/π %, calculate the mechanical advantage.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P = 0.45cm, L = 60cm, Eff = 75/π% <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">VR</td><td style=\"text-align:center;\">(Screw</td><td style=\"text-align:center;\">system)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2πr<hr size=\"1\" />P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2πL<hr size=\"1\" />P</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M.A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Eff% × VR<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">75<hr size=\"1\" />π</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">1<hr size=\"1\" />100</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">2π × 60<hr size=\"1\" />0.45</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">75 × 800<hr size=\"1\" />300</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200</td></tr></table></div></div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2019 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the downward current flows in a straight vertical conductor, the direction of its magnetic field at a point due north of the wire is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Upward</div>", "<div style=\"font-family:Cambria;font-size:17px;\">North</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South</div>", "<div style=\"font-family:Cambria;font-size:17px;\">West</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2019 Model I/img3.png\" style=\"position:relative;max-width:100%;\"/> <br/> At a point due N of the wire, the field is due east, at a point due S of the wire, the field is due west.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS : MAGNETIC FIELD ROUND A STRAIGHT CURRENT CARRYING CONDUCTOR, CIRCULAR WIRE AND SOLENOID"}, {"id": "objective>Physics>2019 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium is sometimes used as the leaf of an electroscope because it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is a light material </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is a good conductor </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is a good insulator </div>", "<div style=\"font-family:Cambria;font-size:17px;\">can be converted into thin sheets </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium is used as the leaf of an electroscope because it is a good conductor. An electroscope is a device used to detect and measure electric charge. It works on the principle that like charges repel each other. When a charged object is brought near the electroscope, the aluminium leaf, being a good conductor, allows the charges to distribute evenly, causing the leaf to repel away from the stem.</div>", "topic": "ELECTROSTATICS : COULOMB’S INVERSE SQUARE LAW ELECTRIC FIELD AND POTENTIAL"}, {"id": "objective>Physics>2019 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above represents the stress-strain graph of a landed wire. Which of these statements is correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">At J, the wire become plastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">J is the yield point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L is the elastic limit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">At K, the wire breaks </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- I is the elastic limit <br/> - the end of the constant part J is the yield point  <br/> - L is the break point.</div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2019 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A supply of 400V is connected across capacitors of 3μf and 6μf in series. Calculate the charge</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>C</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2019 Model I/img5.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> × C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3 × 6<hr size=\"1\" />3 + 6</td></tr></table></div> <br/> = 18/9 = 2μf <br/> Q = CV <br/> ⇒ 2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> × 400 <br/> ⇒ 800 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>C = 8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>C</div>", "topic": "CAPACITORS : CAPACITORS IN SERIES AND PARALLEL"}, {"id": "objective>Physics>2019 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A vibrator causes water ripples to travel across the surface of a tank. The wave travels 50cm in 2s and the distance between successive crests is 5cm. Calculate the frequency of the vibrator </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.2Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25Hz</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The frequency of a wave is calculated by dividing the wave speed by the wavelength. In this case, the wave speed is 50cm/2s = 25cm/s and the wavelength is 5cm. Therefore, the frequency is 25cm/s ÷ 5cm = 5Hz.</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2019 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A thermocouple thermometer is connected to a millivoltmeter which can read up to 10mV. When one junction is in ice at 0°C and the other is steam at 100°C, the millivoltmeter reads 4mV. What is the maximum temperature which this arrangement can measure </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">100°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">248°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">350°</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">θ</span> - t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> = 10, <br/> t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">100</span> - t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> = 4 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">θ</span> - t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span><hr size=\"1\" />t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">100</span> - t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">10<hr size=\"1\" />4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">250°C</td></tr></table></div></div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2019 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An alternating current can induce voltage because it has </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ripple value </div>", "<div style=\"font-family:Cambria;font-size:17px;\">varing magnetic field </div>", "<div style=\"font-family:Cambria;font-size:17px;\">weaker magnetic field than direct current </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high peak value</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As induced voltage is produced by varing magnetic field. The induced voltage is proportional to the rate of change of magnetic flux linking the coil.</div>", "topic": "ELECTROMAGNETIC INDUCTION : INDUCTANCE"}, {"id": "objective>Physics>2019 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The limiting frictional force between two surfaces depends on  <br/> I. the normal reaction between the surfaces <br/> II. the area of surface in contact <br/> III. the relative velocity between the surfaces <br/> IV. the nature of the surfaces </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I & IV only</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- Friction depends on the nature of the surfaces in contact <br/> - Solid friction is independent of the area of the surfaces in contact and the relative velocity between the surfaces.</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2019 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the transformation of matter from the solid to the liquid state, the heat supplied does not produce a temperature increase because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the heat energy is quickly conducted away</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the heat capacity has become very large as the substance melts </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the heat gained is equal to the heat lost by the substance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">all the heat is used to break the bonds holding the molecules of the solid together </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the transformation of matter from the solid to the liquid state, the heat supplied does not produce a temperature increase because all the heat is used to break the bonds holding the molecules of the solid together  <br/>  <br/> </div>", "topic": "CHANGE OF STATE"}, {"id": "objective>Physics>2019 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The statement 'Heat lost by the hot body equals that gained by the cold one' is assumed when determining specific that heat capacity by the method of mixtures. Which of the following validates the assumption? <br/> I. Lagging the Calorimeter <br/> II. Ensuring that only S.I units are used <br/> III. Weighing the calorimeter, the lid and the stirrer.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I & II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I & III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II & III only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The statement 'Heat lost by the hot body equals that gained by the cold one' is a principle of calorimetry. It is validated by lagging the calorimeter to prevent heat loss to the surroundings (I) and by weighing the calorimeter, the lid and the stirrer to ensure accurate measurements (III). Using S.I units (II) is a good practice in any scientific measurement but it does not specifically validate the principle of calorimetry.</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2019 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following graphs is consistent with charle's law?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct  <br/> <img src=\"2019 Model I/img6b.png\" style=\"position:relative;max-width:100%;\"/> <br/> as V α T and temperature is in °C rather than kelvin.</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2019 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the molecular explanation of conduction, heat is transferred by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Free electrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Free atoms </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Free molecules </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Free solids </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- Conduction is explained in terms of the free electrons. <br/> - Convention is explained in terms of the movement of the fluid involved. <br/> - Radiation is explained in terms of invisible electromagnetic wave</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2019 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The conductivity of gases at low pressure can be termed as  <br/> I. hot cathode emission <br/> II. thermo ionic emission <br/> III. cold cathode emission <br/> IV. Field emission</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I & II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II & III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III & IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV & V</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As conduction of gases is at low pressure and high voltage, called field or cold cathode emission.</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2019 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following media allow the transmission of sound waves through them? <br/> I. air <br/> II. liquid <br/> III. solids <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I & II only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I & III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II & III only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II & III</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- sound travels through solids, liquids & gases <br/> - sound travels faster in solid than in liquid & faster in liquid than in gases.</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2019 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The earth's gravitational field intensity at its surface is about  <br/> (G = 6.7 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>, mass of the earth is 6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span>kg, radius of the earth is 6.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>m, g on the earth = 9.8m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.8N/kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.9N/kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0N/kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.8N/kg</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">GMm/d<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">GM<hr size=\"1\" />d<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6.7 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span> × 6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span><hr size=\"1\" />(6.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9.8N<hr size=\"1\" />kg</td></tr></table></div> <br/> E = g = 9.8N/kg</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2019 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A train has an initial velocity of 44m/s and an acceleration of -4m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>. Calculate its velocity after 10secs </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4m/s </div>", "<div style=\"font-family:Cambria;font-size:17px;\">6m/s </div>", "<div style=\"font-family:Cambria;font-size:17px;\">8m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10m/s</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The final velocity of an object can be calculated using the equation v = u + at, where v is the final velocity, u is the initial velocity, a is the acceleration, and t is the time. Substituting the given values, we get v = 44m/s + (-4m/s^2 * 10s) = 4m/s. Therefore, the correct answer is 4m/s.</div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2019 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are parts of the eye <br/> I. Retina <br/> II. Pupil <br/> III. Iris  <br/> The correct equivalent in the camera in the same order are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Diaphragm, Aperture, film</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aperture, Diaphragm, Film</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Film, Diaphragm, Aperture </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Film, Aperture, Diaphragm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- retina is similar to film <br/> - pupil is similar to aperture <br/> - iris is similar to diaphragm</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2019 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">According to kinetic molecular model, in gases </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The particles are closely packed together, they occupy minimum space & are usually arranged in a regular pattern</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The particles occur in clusters with molecules slightly farther apart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The molecule are very fast apart & occupy all the space made available</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The particle vibrate about fixed positions and are held together by the strong intermolecular bonds between them</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In kinetic molecular model, gases are energised and thus moves freely, fast as they occupy specific space</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : KINETIC THEORY"}, {"id": "objective>Physics>2019 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A force of 6N acts horizontally on a stationary mass of 2kg for 4s. The kinetic energy gained by the mass is _________</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">144J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">13J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">169J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F = 6N, m = 2kg, t = 4s, u = 0 (stationary or at rest) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">K.E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mv<hr size=\"1\" />t</td></tr></table></div> from rest <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">K.E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">m(</td><td style=\"text-align:center;\">Ft<hr size=\"1\" />m</td><td style=\"text-align:center;\">)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">6×4<hr size=\"1\" />2</td><td style=\"text-align:center;\">)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">144J</td></tr></table></div></div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2019 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The momentum of a car moving at a constant speed in a circular track </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">can be both positive and negative </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cannot be zero depending on its position in the track </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a centrifugal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">newton's force of gravitation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Momentum (p = mv) is a vector quantity. It depends on the car's mass (m) and velocity (v). Since the car is moving at a constant speed, its momentum will always have a non-zero magnitude. <br/> Even though the direction of the momentum continuously changes as the car moves in a circular track, the magnitude of momentum cannot become zero as long as the car is in motion. <br/> Momentum would only be zero if the car stops moving, which is not the case here.</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2019 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metal rod has a length of 100cm at 200°C. At what temperature will its length be 99.4cm. If the linear expansivity of the material of the nod is 2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-100°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200°C</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 100cm, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 200°C <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 99.4cm, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ?  <br/> α 2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>(T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">110 - 99.4<hr size=\"1\" />100(200 - T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.6<hr size=\"1\" />100(200 - T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)</td></tr></table></div> <br/> 2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> × 100(200 - T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) = 0.6 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">200</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.6<hr size=\"1\" />0.002</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">300°C</td></tr></table></div> <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 200 - 300 = -100°C</div>", "topic": "HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>2019 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The lead-acid accumulator consists of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lead as the positive electrode </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead acid as the negative electrode </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrochloric acid as the electrolyte </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tetraoxosulphate (vi) acid as the electrolyte </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- the positive pole is lead peroxide (PbO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) <br/> - the negative pole is head  <br/> - the electrolyte is H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2019 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When water is boiling, it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gets hotter </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase is mass </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreases in mass </div>", "<div style=\"font-family:Cambria;font-size:17px;\">changes to steam</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When water is boiling, it changes to steam. This is a phase transition from liquid to gas. The temperature of the water does not increase beyond the boiling point under normal atmospheric pressure, hence it does not get hotter. The mass of the water does not increase or decrease, it simply changes state.</div>", "topic": "CHANGE OF STATE : EVAPORATION AND BOILING"}, {"id": "objective>Physics>2019 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture of blue and red pigment when illuminated by white light will appear </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">green </div>", "<div style=\"font-family:Cambria;font-size:17px;\">orange </div>", "<div style=\"font-family:Cambria;font-size:17px;\">purple</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magenta</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture of blue & red pigments i.e parts is purple or violet  <br/> <img src=\"2019 Model I/img7.png\" style=\"position:relative;max-width:100%;\"/> <br/> When illuminated by white light, <br/> V + ROYGBIV = V = Violet or purple.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS : COLOUR MIXING"}, {"id": "objective>Physics>2019 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A siren having a ring of 200s hole makes 132 rev/min. A jet of air is directed on the set of holes. Calculate the frequency and wavelength in air of the note produced (take v = 350m/s)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.795m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.625m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.335m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.125m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">n = 200, S = 132 rev/min, v = 350m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ns</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">132</td><td style=\"text-align:center;\">rev<hr size=\"1\" />min</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">1min<hr size=\"1\" />60s</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">440Hz</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">350<hr size=\"1\" />440</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.795m</td></tr></table></div></div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2019 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A man on a bench will exert the greatest pressure on the bench when he </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lies flat on his back </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lies flat on his belly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stands on both feet </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stands on the toes of one foot</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pressure is defined as force per unit area. When the man stands on the toes of one foot, the area in contact with the bench is smallest, hence the pressure exerted on the bench is greatest.</div>", "topic": "PRESSURE"}, {"id": "objective>Physics>2019 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Gases conduct electricity under</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high pressure & high voltage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">low pressure & low voltage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">normal pressure & low voltage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">low pressure & high voltage </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gases conduct electricity under low pressure and high voltage. This is because at low pressure, the gas molecules are far apart from each other, and at high voltage, the electric field is strong enough to ionize the gas molecules, which allows the gas to conduct electricity.</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2019 Model I>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body moves in SHM between two point 20m on the straight line Joining the points. If the angular speed of the body is 5 rad/s. Calculate its speed when it is 6m from the center of the motion.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50m/s</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From two parts 20m apart  <br/> a = 10m, x = 6m, A = 5 <br/> V = ω&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">A<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>-X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>&nbsp;</span> = 5&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> - 6<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>&nbsp;</span>= 40m/s</div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2019 Model I>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram shows a uniform meter rule AB which balances horizontally at the 90cm mark when a mass of 0.2kg is suspended from B. Calculate the mass of the meter rule.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.05kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.20kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.80kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00kg</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2019 Model I/img9.png\" style=\"position:relative;max-width:100%;\"/> <br/> M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">r</span>(90 - 50) = 0.2(100 - 90) <br/> 40M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">r</span> = 0.2 × 10 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">r</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.05kg</td></tr></table></div></div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>2019 Model I>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium position of objects in any field corresponds to situation of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">equipotential energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximum potential energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimum potential energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximum kinetic energy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium position of objects in any field corresponds to a situation of minimum potential energy. This is because at equilibrium, the forces acting on the object balance each other out, and the object is at its lowest energy state.</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2019 Model I>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The height at which the atmosphere cases to exist is about 80km. If the atmospheric pressure on the ground level is 760mmHg, the pressure at a height of 20km above the ground level is  <br/> (ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> = 13.6g/cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, ρ = 0.00013g/cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">380mmHg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">570mmHg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">190mmHg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">480mmHg</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2019 Model I/RHR4M3.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Since</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">atmospheric</td><td style=\"text-align:center;\">pressure</td><td style=\"text-align:center;\">is</td><td style=\"text-align:center;\">proportional</td><td style=\"text-align:center;\">to</td><td style=\"text-align:center;\">height,</td><td style=\"text-align:center;\">we</td><td style=\"text-align:center;\">interpolate:</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">0 - 760<hr size=\"1\" />x - 760</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80 - 0<hr size=\"1\" />20 - 0</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">-760<hr size=\"1\" />x - 760</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80<hr size=\"1\" />20</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">-760<hr size=\"1\" />x - 760</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4<hr size=\"1\" />1</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">-760</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4(x</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">760)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">-760</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4x</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">3040</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2280</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4x</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2280<hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">570</td><td style=\"text-align:center;\">mmHg</td></tr></table></div></div>", "topic": "PRESSURE : ATMOSPHERIC PRESSURE"}, {"id": "objective>Physics>2019 Model I>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cone is in unstable equilibrium has its potential energy</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decreased </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased </div>", "<div style=\"font-family:Cambria;font-size:17px;\">unchanged </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oscillating </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An object is in unstable equilibrium when a small displacement increases its potential energy and causes it to move further away from its original position. <br/>  <br/> For a cone in unstable equilibrium, if it is slightly disturbed, it will tip over rather than return to its original state. This happens because the center of gravity is high, and any displacement raises its potential energy, making it more unstable.</div>", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY"}, {"id": "objective>Physics>2019 Model I>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mass of 0.5kg is whirled in a vertical circle of radius 2m at a steady rate of 2 rev/s. Calculate the centripetal force</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">164N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">160N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">158N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">172N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">ω = C <br/> W = 2⊼f <br/>  = 2⊼ x 2 <br/>  = 4⊼rad<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/>  <br/> Centripetal force  = mrw<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/>  = 0.5 x 2 x(4⊼)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/>  = 157.95 <br/> Approx. 158 <br/>  <br/> </div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2019 Model I>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body was slightly displaced from its equilibrium position. Which one of the following is a condition for its stable equilibrium</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in the kinetic energy of the body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the potential energy of the body </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the potential energy of the body </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the height of the body</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Stable equilibrium brings about increase in potential energy as the height rises after displacement.</div>", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY"}, {"id": "objective>Physics>2019 Model I>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Why should the eye be placed perpendicularly when reading a meter rule?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">To avoid reading errors due to parallax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To get a larger measurement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To prevent light reflection on the rule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To make the reading process faster</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To avoid reading errors due to parallax <br/> Explanation: Parallax error occurs when the observer's eye is not positioned perpendicular to the scale, leading to an incorrect reading.</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2019 Model I>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When blue and green colours of light are mixed, the resultant colour is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">yellow </div>", "<div style=\"font-family:Cambria;font-size:17px;\">magenta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">black</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When blue and green light are mixed, the resultant color is cyan. This is based on the additive color model, which states that the combination of different wavelengths of light can produce different colors. In this model, blue light (short wavelength) and green light (medium wavelength) combine to produce cyan light.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS : COLOUR MIXING"}, {"id": "objective>Physics>2019 Model I>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the time of flight is 96seconds and the initial velocity, u<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>, is 640ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, calculate the horizontal range through the point of projection.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">84400m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">69000m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">61440m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24000m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Time of flight, T = 96s <br/> R = (Ucosθ) *time* T = 640 × 96 = 61,440m</div>", "topic": "MOTION: PROJECTILES"}, {"id": "objective>Physics>2019 Model I>51", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a body moves with a constant speed and at the same time undergoes an acceleration, its motion is said to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">circular </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oscillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rectilinear </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rotational</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A body moving with constant speed but also undergoing acceleration must be moving in a circular path. This is because in circular motion, even though the speed (magnitude of velocity) might be constant, the direction of velocity is continuously changing, which results in a centripetal acceleration.</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2019 Model I>52", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A lorry travels 10km northwards, 4km eastwards, 6km southwards and 4km westwards to arrive at a point T. <br/> What is the total displacement?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">26km south</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4km north</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6km north </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4km east</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2019 Model I/img10.png\" style=\"position:relative;max-width:100%;\"/> <br/> Displacement = AT = 4km north <br/>  <br/> ∴ the total displacement is 4km north.</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2019 Model I>53", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To determine the weight of an object, you could </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">use a beam balance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">use a spring balance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">use none of the methods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">use any of these methods </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The weight of an object is the force exerted on it due to gravity. This force can be measured using a spring balance, which measures force (in this case, weight) by the extension or compression of a spring. A beam balance, on the other hand, compares the mass of an object to a set of standard masses and does not measure weight directly.</div>", "topic": "MEASUREMENTS AND UNITS : MASS"}, {"id": "objective>Physics>2019 Model I>54", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> A force of 5N acts at a point Y on a rod XYZ as shown in the diagram if XY is 2m, what is the moment of the force about point X?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0 Nm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 Nm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7 Nm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 Nm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Moment of 5N about X = 0 as force 5N is parallel to point X while moments deals with the product of force & perpendicular distance.</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>2019 Model I>55", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a derived unit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Meter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kelvin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Newton</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A derived unit is a unit that is defined by a combination of base units. In the International System of Units (SI), the Newton is a derived unit of force. It is defined as the force required to accelerate a one kilogram mass by one meter per second squared. The other options (Kg, Meter, Kelvin) are base units, not derived units.</div>", "topic": "MEASUREMENTS AND UNITS : DERIVED PHYSICAL QUANTITIES AND THEIR UNITS"}, {"id": "objective>Physics>2019 Model I>56", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The direction of the path taken by light is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Locus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Line</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ray</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Beam</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It generally refers to the line of propagation of waves but is also applied to streams of particles such as the electrons emitted from a cathode or particles emitted by substances exhibiting radioactivity. See cosmic rays; X ray.</div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2019 Model I>57", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In transverse wave, the distance between two adjacent crest is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Wavelength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Half the wavelength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">One quarters of the wavelength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Twice of the wavelength</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a transverse wave, the distance between two adjacent crests (or troughs) is defined as the wavelength. It is the spatial period of the wave—the distance over which the wave's shape repeats. The other options (Half the wavelength, One quarters of the wavelength, Twice of the wavelength) are not correct.</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2019 Model I>58", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is/are correct? <br/> I. When a liquid expands, its density falls <br/> II. The apparent expansion of a liquid is greater than its real expansion <br/> III. When a liquid is heated to a sufficiently high temperature, it changes into liquid</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I & II only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- Liquid expands with increases in temperature <br/> - density decrease with increases in temperature <br/> - this density falls as liquid expands</div>", "topic": "THERMAL EXPANSION : LIQUIDS"}, {"id": "objective>Physics>2019 Model I>59", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Solids have one of the following </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fixed shape, fixed volume, low density & are incompressible </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fixed shape, fixed volume, high density & are incompressible </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fixed shape, fixed volume, low density & are compressible </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fixed shape, fixed volume, high density & are compressible</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Solids are matter that are coagulated together. This is based on force of attraction that allows it to stick together. Thus, it has fixed volume & it is incompressible. </div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : KINETIC THEORY"}, {"id": "objective>Physics>2019 Model I>60", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A force of 16N is applied to a 4.0kg block that is at rest on a month horizontal surface. What is the velocity of the block at 5 sec?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">81m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">23m/s</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F = ma <br/> i.e 16 = 4a <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">16<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></td></tr></table></div> <br/> Using V = u + at (at rest, u = 0) <br/> V = 0 + (4)(5) <br/> V = 20m/s</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2019 Model I>61", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the unit for measuring the amplitude of a sound?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Decibel </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Coulomb</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Flux </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cycles </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The amplitude of a sound is measured in Decibels (dB). Decibel is a logarithmic unit used to express the ratio of two values of a physical quantity, often power or intensity. It is commonly used in acoustics to quantify sound levels.</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : QUALITY, PITCH, INTENSITY AND LOUDNESS"}, {"id": "objective>Physics>2019 Model I>62", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A solid cylinder of radius 3cm has a total surface area of 36πcm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>. Find its height <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8cm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total Surface area = 2πr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 2πrh <br/> 36π = 2π(3)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 2π3h <br/> 36π = 18π + 6πh <br/> 6πh = 18π <br/> h = 3cm</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2019 Model I>63", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a sound wave in air, the adjacent rarefaction and compressions are separated by a distance of 17cm. If the velocity of the sound wave is 340m/s. Determine the frequency.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">14200Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1000Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1890Hz <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2040Hz</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V = 340m/s  <br/> L = 17cm = 0.17m <br/> λ = 2L = 0.34m <br/> V = fλ <br/> 340 = f × 0.34 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">340<hr size=\"1\" />0.34</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1000Hz</td></tr></table></div></div>", "topic": "PROPAGATION OF SOUND WAVES : SPEED OF SOUND"}];
